package biz.edu.service;

import java.util.List;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import com.common.sy.CommonUtils;
import com.common.sy.GridStatus;

import aondev.framework.annotation.ServiceId;
import aondev.framework.annotation.ServiceName;

import biz.edu.dao.CpmsEduRegLstDaoImpl;
import biz.edu.dto.request.CpmsEduRegLstReqDto;
import biz.edu.dto.response.CpmsEduRegLstResDto;

import hsc.framework.online.error.HscException;

import lombok.extern.slf4j.Slf4j;


@Slf4j
@Service
public class CpmsEduRegLstServiceImpl {

    @Autowired
    private CpmsEduRegLstDaoImpl cpmsEduRegLstDaoImpl;

    @ServiceId("SYEDU001/selectEducationRecordList")
    @ServiceName("교육 실적 목록 조회")
    @PreAuthorize("isAuthenticated()")
    @Transactional(readOnly = true)
    public List<CpmsEduRegLstResDto> selectEducationRecordList(CpmsEduRegLstReqDto request) {
        log.debug("Service Method : selectEducationRecordList, Input Param={}", request);
        try {
            return cpmsEduRegLstDaoImpl.selectEducationRecordList(request);
        } catch (Exception e) {
            throw HscException.systemError("교육 실적 목록 조회 중 오류가 발생했습니다.", e);
        }
    }

    @ServiceId("SYEDU001/saveEducationRecordList")
    @ServiceName("교육 실적 저장")
    @PreAuthorize("hasRole('ADMIN') or hasAuthority('ADMIN')")
    @Transactional
    public void saveEducationRecordList(List<CpmsEduRegLstResDto> list) {
        log.debug("Service Method : saveEducationRecordList, Input Param={}", list);
        try {
            List<CpmsEduRegLstResDto> insertList = CommonUtils.filterByStatus(list, GridStatus.INSERTED);
            List<CpmsEduRegLstResDto> updateList = CommonUtils.filterByStatus(list, GridStatus.UPDATED);
            List<CpmsEduRegLstResDto> deleteList = CommonUtils.filterByStatus(list, GridStatus.DELETED);

            for (CpmsEduRegLstResDto dto : insertList) {
                enrichUserInfo(dto);
                if (dto.getId() == null || dto.getId().isEmpty()) {
                    dto.setId("");
                }
                int duplicateCount = cpmsEduRegLstDaoImpl.selectDuplicateEducationRecord(dto);
                if (duplicateCount > 0) {
                    throw new HscException("CM0001");
                }
                cpmsEduRegLstDaoImpl.insertEducationRecord(dto);
            }

            for (CpmsEduRegLstResDto dto : updateList) {
                enrichUserInfo(dto);
                int duplicateCount = cpmsEduRegLstDaoImpl.selectDuplicateEducationRecord(dto);
                if (duplicateCount > 0) {
                    throw new HscException("CM0001");
                }
                cpmsEduRegLstDaoImpl.updateEducationRecord(dto);
            }

            for (CpmsEduRegLstResDto dto : deleteList) {
                cpmsEduRegLstDaoImpl.deleteEducationRecord(dto);
            }
        } catch (HscException e) {
            throw e;
        } catch (Exception e) {
            throw HscException.systemError("교육 실적 저장 중 오류가 발생했습니다.", e);
        }
    }

    @ServiceId("SYEDU001/uploadEducationRecordExcel")
    @ServiceName("교육 실적 엑셀 업로드")
    @PreAuthorize("hasRole('ADMIN') or hasAuthority('ADMIN')")
    @Transactional
    public void uploadEducationRecordExcel(List<CpmsEduRegLstResDto> list) {
        log.debug("Service Method : uploadEducationRecordExcel, Input Param={}", list);
        try {
            for (CpmsEduRegLstResDto dto : list) {
                dto.setStatus(GridStatus.INSERTED.name());
                enrichUserInfo(dto);
                if (dto.getId() == null || dto.getId().isEmpty()) {
                    dto.setId("");
                }
                int duplicateCount = cpmsEduRegLstDaoImpl.selectDuplicateEducationRecord(dto);
                if (duplicateCount > 0) {
                    throw new HscException("CM0001");
                }
                cpmsEduRegLstDaoImpl.insertEducationRecord(dto);
            }
        } catch (HscException e) {
            throw e;
        } catch (Exception e) {
            throw HscException.systemError("교육 실적 엑셀 업로드 중 오류가 발생했습니다.", e);
        }
    }

    private void enrichUserInfo(CpmsEduRegLstResDto dto) {
        if (dto == null) {
            return;
        }
        if (dto.getUserId() != null && !dto.getUserId().isEmpty()) {
            if (dto.getUserName() == null || dto.getUserName().isEmpty()) {
                dto.setUserName(dto.getUserId());
            }
            if (dto.getDepartmentName() == null || dto.getDepartmentName().isEmpty()) {
                dto.setDepartmentName("UNKNOWN");
            }
        }
    }
}
